import numpy as np

def simulate_u_shape_accuracy(position):
    return 0.95 - 0.4 * (1.0 - (2.0 * position - 1.0)**2)

def run_practice():
    acc_start = simulate_u_shape_accuracy(0.0)
    acc_mid = simulate_u_shape_accuracy(0.5)
    acc_end = simulate_u_shape_accuracy(1.0)
    assert acc_start > acc_mid
    assert acc_end > acc_mid
    print('[PASS] Lost-in-the-middle accuracy checks validated.')

if __name__ == '__main__':
    run_practice()
